define("block_ragchat/chat",["core/ajax","core/notification"],function(Ajax,Notification){"use strict";
const init=(config)=>{
    const root=document.querySelector("#block-ragchat-"+config.blockid);
    if(!root)return;
    const form=root.querySelector(".ragchat-form");
    const input=root.querySelector(".ragchat-input");
    const messages=root.querySelector(".ragchat-messages");
    const sendBtn=root.querySelector(".ragchat-send");
    if(!form||!input||!messages||!sendBtn)return;
    // In-memory conversation history [{role,content}, ...]
    const history=[];
    form.addEventListener("submit",function(e){
        e.preventDefault();
        const question=input.value.trim();
        if(!question)return;
        appendMessage(messages,"user",escapeHtml(question));
        input.value="";
        const loadingBubble=appendLoadingBubble(messages,config.strings.thinking);
        setLoading(sendBtn,input,true,config.strings.thinking);
        // Snapshot history before adding current question
        const historySnapshot=history.slice();
        Ajax.call([{
            methodname:"block_ragchat_send_message",
            args:{question:question,collectionid:config.collectionid,courseid:config.courseid,instanceid:config.instanceid||0,history:historySnapshot}
        }])[0].then(function(result){
            if(loadingBubble&&loadingBubble.parentNode){loadingBubble.parentNode.removeChild(loadingBubble);}
            if(!result.success){
                appendMessage(messages,"error",escapeHtml(result.error||config.strings.error_generic));
            } else {
                appendAnswer(messages,result.answer,result.sources,config.strings,result.norag);
                // Update history only on success
                history.push({role:"user",content:question});
                history.push({role:"assistant",content:result.answer});
                // Cap to last 20 turns (10 exchanges)
                if(history.length>20){history.splice(0,history.length-20);}
            }
            return result;
        }).catch(function(err){
            if(loadingBubble&&loadingBubble.parentNode){loadingBubble.parentNode.removeChild(loadingBubble);}
            var msg=(err&&err.message)?err.message:config.strings.error_generic;
            appendMessage(messages,"error",escapeHtml(msg));
        }).always(function(){
            setLoading(sendBtn,input,false,config.strings.send);
            scrollToBottom(messages);
        });
    });
};
const appendMessage=(container,role,text)=>{
    const div=document.createElement("div");
    div.className="ragchat-bubble ragchat-bubble--"+role;
    div.innerHTML=text;
    container.appendChild(div);
    scrollToBottom(container);
    return div;
};
const appendLoadingBubble=(container,label)=>{
    const div=document.createElement("div");
    div.className="ragchat-bubble ragchat-bubble--loading";
    div.textContent=label;
    container.appendChild(div);
    scrollToBottom(container);
    return div;
};
const appendAnswer=(container,answer,sources,strings,norag)=>{
    const div=document.createElement("div");
    div.className="ragchat-bubble ragchat-bubble--assistant";
    const answerEl=document.createElement("p");
    answerEl.className="ragchat-answer";
    answerEl.innerHTML=escapeHtml(answer).replace(/\n/g,"<br>");
    div.appendChild(answerEl);
    if(sources&&sources.length>0){
        const sourcesEl=document.createElement("details");
        sourcesEl.className="ragchat-sources";
        const summary=document.createElement("summary");
        summary.textContent=strings.sources;
        sourcesEl.appendChild(summary);
        const ul=document.createElement("ul");
        sources.forEach(function(src){
            const li=document.createElement("li");
            const titleEl=src.url?'<a href="'+escapeHtml(src.url)+'" target="_blank" rel="noopener">'+escapeHtml(src.title)+"</a>":escapeHtml(src.title);
            li.innerHTML=titleEl+"<br><small>"+escapeHtml(src.excerpt)+"</small>";
            ul.appendChild(li);
        });
        sourcesEl.appendChild(ul);
        div.appendChild(sourcesEl);
    }
    if(norag){
        const noragEl=document.createElement("p");
        noragEl.className="ragchat-norag-notice text-muted small";
        noragEl.textContent=strings.norag_disclaimer;
        div.appendChild(noragEl);
    }
    const disclaimer=document.createElement("p");
    disclaimer.className="ragchat-disclaimer";
    disclaimer.textContent=strings.ai_disclaimer;
    div.appendChild(disclaimer);
    container.appendChild(div);
};
const setLoading=(btn,input,loading,label)=>{btn.disabled=loading;input.disabled=loading;btn.textContent=label;};
const scrollToBottom=(el)=>{el.scrollTop=el.scrollHeight;};
const escapeHtml=(str)=>String(str).replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;").replace(/"/g,"&quot;").replace(/'/g,"&#39;");
return{init:init};
});
